CREATE   PROC [dbo].[TR_BAOGIA_SANPHAM_TUDONG_GVA]
(
	@masp nvarchar(200),
	@tygia_usd float
)
AS
BEGIN
	--DECLARE @tygia_usd float = 25400
	--DECLARE @masp nvarchar(200) = '2511-0237Z_2511_BST'

	IF @tygia_usd IS NULL OR @tygia_usd <= 0
		SET @tygia_usd = 1

	SELECT * 
	INTO #BAOGIA_GOVAN
	FROM tr_baogia_govan WHERE 0 = 1

	DECLARE @dongia_son float
	SELECT @dongia_son = B.dongia
	FROM tr_sanpham A INNER JOIN tr_color B ON A.mausac = B.code
	WHERE A.masp = @masp

	IF @dongia_son IS NULL
		SET @dongia_son = 0

	SELECT A.stt, A.chitiet, A.nguyenlieu,
		A.veneer_matchinh, C.loaihang AS ten_veneer_matchinh, 
		A.veneer_matphu, D.loaihang AS ten_veneer_matphu, 
		A.veneer_dan_canh, E.loaihang AS ten_veneer_dan_canh, 
		A.uv_matchinh, A.uv_matphu, A.uv_canhngan, A.uv_canhdai,
		A.dayy_tc, A.rong_tc, A.dai_tc, A.soluong_tc,
		mong = A.mong1 + A.mong2,
		m3 = CASE WHEN A.nguyenlieu NOT IN ('', '0') THEN (A.dayy_tc * A.rong_tc * A.dai_tc * A.soluong_tc) / 1000000000 ELSE 0 END,
		dientich = CASE WHEN A.nguyenlieu NOT IN ('', '0') THEN ((A.dai_tc * A.rong_tc * 2) + (A.dai_tc * A.dayy_tc * 2) + (A.dayy_tc * A.rong_tc*2) * A.soluong_tc) / 1000000 ELSE 0 END,
		dongia_son = @dongia_son,
		B.dongia_nguyenlieu, B.thanhtien_govan, B.thanhtien_veneer,
		A.ghichu, B.baoGiaID, A.mact, A.masp, B.id,
		B.tyle_haohut, B.dokho_giacong, B.idChiPhiGiaCong, B.dongia_giacong, B.thanhtien_giacong,
		B.dongia_nhancong, B.dongia_nhancong1, B.dongia_nhancong2, B.dongia_nhancong3, B.dongia_nhancong4,
		B.dongia_nhancong5, B.dongia_nhancong6, B.dongia_nhancong7, B.dongia_nhancong8, B.dongia_nhancong9,
		rowId = NEWID()
	INTO #DINHMUC_GOVAN
	FROM tr_dinhmuc_govan A
		LEFT JOIN #BAOGIA_GOVAN B ON A.masp = B.masp
		LEFT JOIN tr_baogia_chiphi_veneer C ON A.veneer_matchinh = C.id
		LEFT JOIN tr_baogia_chiphi_veneer D ON A.veneer_matphu = D.id
		LEFT JOIN tr_baogia_chiphi_veneer E ON A.veneer_dan_canh = E.id
	WHERE A.masp = @masp

	DECLARE @nguyenlieu nvarchar(200) = '';
	DECLARE @dayy_tc float = 0;
	DECLARE @rong_tc float = 0;
	DECLARE @dai_tc float = 0;
	DECLARE @soluong_tc float = 0;
	DECLARE @m3_tc float = 0;
	DECLARE @veneer_matchinh int = 0;
	DECLARE @veneer_matphu int = 0;
	DECLARE @veneer_dan_canh int = 0;
	DECLARE @rowId uniqueidentifier;

	DECLARE CUR CURSOR LOCAL FOR
		SELECT rowId, nguyenlieu, dayy_tc, rong_tc, dai_tc, soluong_tc, m3,
			veneer_matchinh, veneer_matphu, veneer_dan_canh
		FROM #DINHMUC_GOVAN
	OPEN CUR 
	FETCH NEXT FROM CUR INTO @rowId, @nguyenlieu, @dayy_tc, @rong_tc, @dai_tc, @soluong_tc, @m3_tc, @veneer_matchinh, @veneer_matphu, @veneer_dan_canh
	WHILE @@FETCH_STATUS = 0
	BEGIN
		-- TÍNH GIÁ VENEER
		DECLARE @dongia1_veneer float = 0, @dongia2_veneer float = 0, @dongia3_veneer float = 0;
		DECLARE @thanhtien_veneer1 float = 0, @thanhtien_veneer2 float = 0, @thanhtien_veneer3 float = 0;

		SELECT @dongia1_veneer = COALESCE(CASE WHEN @dai_tc >= 2000 THEN dongia2 ELSE dongia1 END, 0)
		FROM tr_baogia_chiphi_veneer
		WHERE id = @veneer_matchinh

		SELECT @dongia2_veneer = COALESCE(CASE WHEN @dai_tc >= 2000 THEN dongia2 ELSE dongia1 END, 0)
		FROM tr_baogia_chiphi_veneer
		WHERE id = @veneer_matphu

		SELECT @dongia3_veneer = COALESCE(CASE WHEN @dai_tc >= 2000 THEN dongia2 ELSE dongia1 END, 0)
		FROM tr_baogia_chiphi_veneer
		WHERE id = @veneer_dan_canh
		
		SET @thanhtien_veneer1 = ((@rong_tc * @dai_tc * @soluong_tc)/1000000) * @dongia1_veneer;
		SET @thanhtien_veneer2 = ((@rong_tc * @dai_tc * @soluong_tc)/1000000) * @dongia2_veneer;
		SET @thanhtien_veneer3 = ((@dayy_tc * @dai_tc * @soluong_tc * 2)/1000000) * @dongia3_veneer;

		-- TÍNH GIÁ GỖ VÁN
		DECLARE @dongia_gva float = 0;
		DECLARE @nhancong float = 0;
		DECLARE @nhancong1 float = 0;
		DECLARE @nhancong2 float = 0;
		DECLARE @nhancong3 float = 0;
		DECLARE @nhancong4 float = 0;
		DECLARE @nhancong5 float = 0;
		DECLARE @nhancong6 float = 0;
		DECLARE @nhancong7 float = 0;
		DECLARE @nhancong8 float = 0;
		DECLARE @nhancong9 float = 0;
		DECLARE @loaitien nvarchar(50) = '';

		SELECT @dongia_gva = dongia, 
			@nhancong = nhancong,
			@nhancong1 = nhancong1,
			@nhancong2 = nhancong2,
			@nhancong3 = nhancong3,
			@nhancong4 = nhancong4,
			@nhancong5 = nhancong5,
			@nhancong6 = nhancong6,
			@nhancong7 = nhancong7,
			@nhancong8 = nhancong8,
			@nhancong9 = nhancong9,
			@loaitien = loaitien 
		FROM dbo.FN_DONGIA_NGUYENLIEU_GVA2(@nguyenlieu, @dayy_tc, @dai_tc);

		IF @loaitien = 'USD'
		BEGIN
			SET @dongia_gva = @dongia_gva * @tygia_usd;
			SET @nhancong = @nhancong * @tygia_usd;
			SET @nhancong1 = @nhancong1 * @tygia_usd;
			SET @nhancong2 = @nhancong2 * @tygia_usd;
			SET @nhancong3 = @nhancong3 * @tygia_usd;
			SET @nhancong4 = @nhancong4 * @tygia_usd;
			SET @nhancong5 = @nhancong5 * @tygia_usd;
			SET @nhancong6 = @nhancong6 * @tygia_usd;
			SET @nhancong7 = @nhancong7 * @tygia_usd;
			SET @nhancong8 = @nhancong8 * @tygia_usd;
			SET @nhancong9 = @nhancong9 * @tygia_usd;
		END

		UPDATE #DINHMUC_GOVAN
		SET dongia_nguyenlieu = @dongia_gva,
			thanhtien_govan = @dongia_gva * @m3_tc,
			thanhtien_veneer = @thanhtien_veneer1 + @thanhtien_veneer2 + @thanhtien_veneer3,
			dongia_nhancong = @nhancong,
			dongia_nhancong1 = @nhancong1,
			dongia_nhancong2 = @nhancong2,
			dongia_nhancong3 = @nhancong3,
			dongia_nhancong4 = @nhancong4,
			dongia_nhancong5 = @nhancong5,
			dongia_nhancong6 = @nhancong6,
			dongia_nhancong7 = @nhancong7,
			dongia_nhancong8 = @nhancong8,
			dongia_nhancong9 = @nhancong9
		WHERE rowId = @rowId

		FETCH NEXT FROM CUR INTO @rowId, @nguyenlieu, @dayy_tc, @rong_tc, @dai_tc, @soluong_tc, @m3_tc, @veneer_matchinh, @veneer_matphu, @veneer_dan_canh
	END
	CLOSE CUR;
	DEALLOCATE CUR;

	SELECT * FROM #DINHMUC_GOVAN ORDER BY stt

	DROP TABLE #BAOGIA_GOVAN, #DINHMUC_GOVAN
END


